import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './Auth.css';

const Profile = () => {
    const [user, setUser] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchProfile = async () => {
            const token = localStorage.getItem('token');
            if (!token) {
                navigate('/login');
                return;
            }
            try {
                // Mock fetching profile from localStorage
                // const res = await axios.get('http://localhost:5001/api/auth/profile', ...);
                setTimeout(() => {
                    const storedUser = localStorage.getItem('user');
                    if (storedUser) {
                        setUser(JSON.parse(storedUser));
                    } else {
                        // Fallback if no user stored but token exists (shouldn't happen in new flow)
                        throw new Error('No user data');
                    }
                }, 500);
            } catch (error) {
                console.error("Profile fetch error", error);
                localStorage.removeItem('token');
                localStorage.removeItem('user');
                navigate('/login');
            }
        };
        fetchProfile();
    }, [navigate]);

    if (!user) return <div className="auth-title">Loading...</div>;

    return (
        <div className="profile-container">
            <div className="profile-header">
                <div className="profile-avatar">
                    {user.username.charAt(0).toUpperCase()}
                </div>
                <div className="profile-info">
                    <h1>{user.username}</h1>
                    <p>{user.email}</p>
                    <p>Member since {new Date(user.createdAt).toLocaleDateString()}</p>
                </div>
            </div>
            <button onClick={() => {
                localStorage.removeItem('token');
                navigate('/login');
            }} className="auth-button" style={{ width: 'auto', padding: '0.8rem 2rem' }}>Logout</button>
        </div>
    );
};

export default Profile;
